(41,$t$1.7E$t$,$r$171_180$r$,$d$medium$d$,$s$What time does the clock show?$s$,$v$<svg viewBox="0 0 620 220" xmlns="http://www.w3.org/2000/svg"><image href="/grade1-math-50-preview-assets/figure-26.svg" x="0" y="0" width="620" height="220" preserveAspectRatio="xMinYMin meet"/></svg>$v$,$e$The long hand points to 6, which means 30 minutes. The hour hand is between 10 and 11.$e$,$n$Original Grade 1 math preview seed: TestingMom reference batch 1$n$,$c$[{"label":"A","body":"10:00","is_correct":false,"sort_order":1,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"B","body":"10:30","is_correct":true,"sort_order":2,"misconception":null,"misconception_tag":null},{"label":"C","body":"6:10","is_correct":false,"sort_order":3,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"D","body":"11:30","is_correct":false,"sort_order":4,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"}]$c$::jsonb),
(42,$t$1.7E$t$,$r$181_190$r$,$d$hard$d$,$s$It is 8:00. What time is 3 hours later?$s$,$v$<svg viewBox="0 0 620 220" xmlns="http://www.w3.org/2000/svg"><image href="/grade1-math-50-preview-assets/figure-27.svg" x="0" y="0" width="620" height="220" preserveAspectRatio="xMinYMin meet"/></svg>$v$,$e$Count 3 hours after 8:00: 9:00, 10:00, 11:00.$e$,$n$Original Grade 1 math preview seed: TestingMom reference batch 1$n$,$c$[{"label":"A","body":"10:00","is_correct":false,"sort_order":1,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"B","body":"11:00","is_correct":true,"sort_order":2,"misconception":null,"misconception_tag":null},{"label":"C","body":"12:00","is_correct":false,"sort_order":3,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"D","body":"5:00","is_correct":false,"sort_order":4,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"}]$c$::jsonb),
(43,$t$1.7E$t$,$r$181_190$r$,$d$hard$d$,$s$It is 6:30. What time was 1 hour before?$s$,$v$<svg viewBox="0 0 620 220" xmlns="http://www.w3.org/2000/svg"><image href="/grade1-math-50-preview-assets/figure-28.svg" x="0" y="0" width="620" height="220" preserveAspectRatio="xMinYMin meet"/></svg>$v$,$e$One hour before 6:30 is 5:30.$e$,$n$Original Grade 1 math preview seed: TestingMom reference batch 1$n$,$c$[{"label":"A","body":"5:30","is_correct":true,"sort_order":1,"misconception":null,"misconception_tag":null},{"label":"B","body":"6:00","is_correct":false,"sort_order":2,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"C","body":"7:30","is_correct":false,"sort_order":3,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"},{"label":"D","body":"5:00","is_correct":false,"sort_order":4,"misconception":"Confused the hour hand and minute hand.","misconception_tag":"time_clock_reading"}]$c$::jsonb),
(44,$t$1.8C$t$,$r$171_180$r$,$d$medium$d$,$s$Which snack got the fewest votes?$s$,$v$<svg viewBox="0 0 620 220" xmlns="http://www.w3.org/2000/svg"><image href="/grade1-math-50-preview-assets/figure-29.svg" x="0" y="0" width="620" height="220" preserveAspectRatio="xMinYMin meet"/></svg>$v$,$e$The crackers bar is the shortest. It shows 4 votes.$e$,$n$Original Grade 1 math preview seed: TestingMom reference batch 1$n$,$c$[{"label":"A","body":"Fruit","is_correct":false,"sort_order":1,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"},{"label":"B","body":"Crackers","is_correct":true,"sort_order":2,"misconception":null,"misconception_tag":null},{"label":"C","body":"Cheese","is_correct":false,"sort_order":3,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"},{"label":"D","body":"Fruit and cheese","is_correct":false,"sort_order":4,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"}]$c$::jsonb),
(45,$t$1.8C$t$,$r$181_190$r$,$d$hard$d$,$s$How many more chose fruit than crackers?$s$,$v$<svg viewBox="0 0 620 220" xmlns="http://www.w3.org/2000/svg"><image href="/grade1-math-50-preview-assets/figure-30.svg" x="0" y="0" width="620" height="220" preserveAspectRatio="xMinYMin meet"/></svg>$v$,$e$Fruit has 7 votes and crackers has 4. 7 - 4 = 3.$e$,$n$Original Grade 1 math preview seed: TestingMom reference batch 1$n$,$c$[{"label":"A","body":"2","is_correct":false,"sort_order":1,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"},{"label":"B","body":"3","is_correct":true,"sort_order":2,"misconception":null,"misconception_tag":null},{"label":"C","body":"4","is_correct":false,"sort_order":3,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"},{"label":"D","body":"11","is_correct":false,"sort_order":4,"misconception":"Read the wrong bar, row, or count in the graph.","misconception_tag":"graph_or_table_misread"}]$c$::jsonb)
), ins as (insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format) select 'math'::map_subject,1,s.id,null,seed.rit_band::map_rit_band,seed.difficulty::map_difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq' from seed join map_standards s on s.grade=1 and s.subject='math'::map_subject and s.teks_code=seed.teks_code where not exists (select 1 from map_questions q where q.grade=1 and q.subject='math'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.stem_image_svg is not distinct from seed.stem_image_svg) returning id,stem,stem_image_svg,source_note) insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order) select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order from ins join seed on seed.stem=ins.stem and seed.source_note=ins.source_note and seed.stem_image_svg is not distinct from ins.stem_image_svg cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1),body text,is_correct boolean,misconception text,misconception_tag text,sort_order smallint);